mapper.insert:
insert into activity_participant (
    activity_id, user_id, registration_time, attendance_status, 
    special_needs, emergency_contact, emergency_phone, notes
) values (
    #{activityId}, #{userId}, #{registrationTime}, #{attendanceStatus}, 
    #{specialNeeds}, #{emergencyContact}, #{emergencyPhone}, #{notes}
)

mapper.select:
select ap.id, ap.activity_id, ap.user_id, ap.registration_time, ap.attendance_status, ap.check_in_time, ap.check_out_time, ap.rating, ap.feedback, ap.special_needs, ap.emergency_contact, ap.emergency_phone, ap.notes, ap.create_time, ap.update_time, a.title as activity_title, a.activity_date, a.location as activity_location, a.cost, u.name as user_name from activity_participant ap left join activity a on ap.activity_id = a.id left join user u on ap.user_id = u.id
and ap.activity_id = #{activityId} and ap.user_id = #{userId} and ap.attendance_status = #{attendanceStatus}
order by ap.registration_time desc

select ap.id, ap.activity_id, ap.user_id, ap.registration_time, ap.attendance_status, ap.check_in_time, ap.check_out_time, ap.rating, ap.feedback, ap.special_needs, ap.emergency_contact, ap.emergency_phone, ap.notes, ap.create_time, ap.update_time, a.title as activity_title, a.activity_date, a.location as activity_location, a.cost, u.name as user_name from activity_participant ap left join activity a on ap.activity_id = a.id left join user u on ap.user_id = u.id
and ap.activity_id = #{activityId} and ap.user_id = #{userId} and ap.attendance_status = #{attendanceStatus}
order by ap.registration_time desc

select 
from activity_participant
where activity_id = #{activityId} and user_id = #{userId}

